def select_action(obs: np.ndarray) -> int:
    if obs[101] == 0:
        return 1

    ball_x = obs[99]
    ball_y = obs[101]
    paddle_x = obs[72]

    if not hasattr(select_action, "last_ball_y"):
        select_action.last_ball_y = ball_y
        select_action.last_ball_x = ball_x
        if ball_x < paddle_x:
            return 3
        elif ball_x > paddle_x:
            return 2
        return 0

    last_y = select_action.last_ball_y
    last_x = select_action.last_ball_x
    select_action.last_ball_y = ball_y
    select_action.last_ball_x = ball_x

    dy = ball_y - last_y
    dx = ball_x - last_x

    if dy >= 0:
        target_x = ball_x
    else:
        # Predict landing after bouncing off top wall (y=0) and then to paddle y ~192
        if dy != 0:
            time_to_land = (ball_y + 192) / abs(dy)
            horiz_off = dx * time_to_land
            target_x = ball_x + horiz_off
            # Mirror wall bounces
            if target_x < 0:
                target_x = -target_x
            elif target_x > 160:
                target_x = 320 - target_x
            target_x = max(0, min(160, target_x))
        else:
            target_x = ball_x

    # Add a 10-pixel lateral bias for aggressive tracking
    if target_x > ball_x:
        target_x += 10
    else:
        target_x -= 10
    target_x = max(55, min(191, target_x))

    if target_x < paddle_x:
        return 3
    elif target_x > paddle_x:
        return 2
    return 0
